import{_ as a,o as i,c as l,a2 as e}from"./chunks/framework.BRk9mohw.js";const k=JSON.parse('{"title":"Find Skills（查找技能）","description":"","frontmatter":{"名称":"find-skills","描述":"当用户询问\\"如何做 X\\"、\\"为 X 找一个技能\\"、\\"有能...的技能吗\\"或表示有兴趣扩展代理能力时，帮助用户发现和安装代理技能。此技能应在用户寻找可能已存在技能的功能时使用。"},"headers":[],"relativePath":"skills/find-skills.md","filePath":"skills/find-skills.md"}'),t={name:"skills/find-skills.md"};function n(p,s,o,d,r,c){return i(),l("div",null,[...s[0]||(s[0]=[e(`<h1 id="find-skills-查找技能" tabindex="-1">Find Skills（查找技能） <a class="header-anchor" href="#find-skills-查找技能" aria-label="Permalink to &quot;Find Skills（查找技能）&quot;">​</a></h1><p>此技能帮助您从开放代理技能生态系统中发现和安装技能。</p><h2 id="何时使用此技能" tabindex="-1">何时使用此技能 <a class="header-anchor" href="#何时使用此技能" aria-label="Permalink to &quot;何时使用此技能&quot;">​</a></h2><p>当用户存在以下情况时，使用此技能：</p><ul><li>询问&quot;如何做 X&quot;，其中 X 可能是已有技能的常见任务</li><li>说&quot;为 X 找一个技能&quot;或&quot;有 X 的技能吗&quot;</li><li>询问&quot;你能做 X 吗&quot;，其中 X 是专业能力</li><li>表示有兴趣扩展代理能力</li><li>想要搜索工具、模板或工作流</li><li>提到希望有特定领域的帮助（设计、测试、部署等）</li></ul><h2 id="什么是-skills-cli" tabindex="-1">什么是 Skills CLI？ <a class="header-anchor" href="#什么是-skills-cli" aria-label="Permalink to &quot;什么是 Skills CLI？&quot;">​</a></h2><p>Skills CLI（<code>npx skills</code>）是开放代理技能生态系统的包管理器。技能是模块化包，用专门的知识、工作流和工具扩展代理能力。</p><p><strong>关键命令：</strong></p><ul><li><code>npx skills find [query]</code> - 交互式搜索或按关键词搜索技能</li><li><code>npx skills add &lt;package&gt;</code> - 从 GitHub 或其他来源安装技能</li><li><code>npx skills check</code> - 检查技能更新</li><li><code>npx skills update</code> - 更新所有已安装的技能</li></ul><p><strong>浏览技能请访问：</strong> <a href="https://skills.sh/" target="_blank" rel="noreferrer">https://skills.sh/</a></p><h2 id="如何帮助用户找到技能" tabindex="-1">如何帮助用户找到技能 <a class="header-anchor" href="#如何帮助用户找到技能" aria-label="Permalink to &quot;如何帮助用户找到技能&quot;">​</a></h2><h3 id="第一步-了解他们需要什么" tabindex="-1">第一步：了解他们需要什么 <a class="header-anchor" href="#第一步-了解他们需要什么" aria-label="Permalink to &quot;第一步：了解他们需要什么&quot;">​</a></h3><p>当用户请求帮助时，确定：</p><ol><li>领域（例如 React、测试、设计、部署）</li><li>具体任务（例如编写测试、创建动画、审查 PR）</li><li>这是否是一个足够常见的任务，可能存在相应技能</li></ol><h3 id="第二步-搜索技能" tabindex="-1">第二步：搜索技能 <a class="header-anchor" href="#第二步-搜索技能" aria-label="Permalink to &quot;第二步：搜索技能&quot;">​</a></h3><p>使用相关查询运行查找命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> find</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [query]</span></span></code></pre></div><p>例如：</p><ul><li>用户问&quot;如何让我的 React 应用更快？&quot; → <code>npx skills find react performance</code></li><li>用户问&quot;你能帮我审查 PR 吗？&quot; → <code>npx skills find pr review</code></li><li>用户说&quot;我需要创建一个变更日志&quot; → <code>npx skills find changelog</code></li></ul><p>命令将返回如下结果：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 npx skills add &lt;owner/repo@skill&gt; 安装</span></span>
<span class="line"><span></span></span>
<span class="line"><span>vercel-labs/agent-skills@vercel-react-best-practices</span></span>
<span class="line"><span>└ https://skills.sh/vercel-labs/agent-skills/vercel-react-best-practices</span></span></code></pre></div><h3 id="第三步-向用户展示选项" tabindex="-1">第三步：向用户展示选项 <a class="header-anchor" href="#第三步-向用户展示选项" aria-label="Permalink to &quot;第三步：向用户展示选项&quot;">​</a></h3><p>找到相关技能后，向用户展示：</p><ol><li>技能名称及其功能</li><li>他们可以运行的安装命令</li><li>了解更多的 skills.sh 链接</li></ol><p>示例回复：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我找到一个可能有帮助的技能！&quot;vercel-react-best-practices&quot; 技能提供来自 Vercel Engineering 的 React 和 Next.js 性能优化指南。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>安装方法：</span></span>
<span class="line"><span>npx skills add vercel-labs/agent-skills@vercel-react-best-practices</span></span>
<span class="line"><span></span></span>
<span class="line"><span>了解更多：https://skills.sh/vercel-labs/agent-skills/vercel-react-best-practices</span></span></code></pre></div><h3 id="第四步-提供安装" tabindex="-1">第四步：提供安装 <a class="header-anchor" href="#第四步-提供安装" aria-label="Permalink to &quot;第四步：提供安装&quot;">​</a></h3><p>如果用户想继续，可以为他们安装技能：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">owner/repo@skil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p><code>-g</code> 标志表示全局安装（用户级别），<code>-y</code> 跳过确认提示。</p><h2 id="常见技能类别" tabindex="-1">常见技能类别 <a class="header-anchor" href="#常见技能类别" aria-label="Permalink to &quot;常见技能类别&quot;">​</a></h2><p>搜索时，考虑这些常见类别：</p><table tabindex="0"><thead><tr><th>类别</th><th>示例查询</th></tr></thead><tbody><tr><td>Web 开发</td><td>react, nextjs, typescript, css, tailwind</td></tr><tr><td>测试</td><td>testing, jest, playwright, e2e</td></tr><tr><td>DevOps</td><td>deploy, docker, kubernetes, ci-cd</td></tr><tr><td>文档</td><td>docs, readme, changelog, api-docs</td></tr><tr><td>代码质量</td><td>review, lint, refactor, best-practices</td></tr><tr><td>设计</td><td>ui, ux, design-system, accessibility</td></tr><tr><td>生产力</td><td>workflow, automation, git</td></tr></tbody></table><h2 id="有效搜索的技巧" tabindex="-1">有效搜索的技巧 <a class="header-anchor" href="#有效搜索的技巧" aria-label="Permalink to &quot;有效搜索的技巧&quot;">​</a></h2><ol><li><strong>使用具体关键词</strong>：&quot;react testing&quot; 比单纯 &quot;testing&quot; 更好</li><li><strong>尝试替代术语</strong>：如果 &quot;deploy&quot; 不起作用，尝试 &quot;deployment&quot; 或 &quot;ci-cd&quot;</li><li><strong>检查热门来源</strong>：许多技能来自 <code>vercel-labs/agent-skills</code> 或 <code>ComposioHQ/awesome-claude-skills</code></li></ol><h2 id="未找到技能时" tabindex="-1">未找到技能时 <a class="header-anchor" href="#未找到技能时" aria-label="Permalink to &quot;未找到技能时&quot;">​</a></h2><p>如果不存在相关技能：</p><ol><li>承认未找到现有技能</li><li>提供使用一般能力直接帮助他们完成任务的选项</li><li>建议用户可以使用 <code>npx skills init</code> 创建自己的技能</li></ol><p>示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我搜索了与 &quot;xyz&quot; 相关的技能，但没有找到匹配项。</span></span>
<span class="line"><span>我仍然可以直接帮助您完成这个任务！您希望我继续吗？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果这是您经常做的事情，您可以创建自己的技能：</span></span>
<span class="line"><span>npx skills init my-xyz-skill</span></span></code></pre></div>`,40)])])}const u=a(t,[["render",n]]);export{k as __pageData,u as default};
